export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i += 1
    } else if (arg.includes('=')) {
      // --key=value syntax
      const [key, value] = arg.slice(2).split('=', 2)
      result[key] = value
      i += 1
    } else {
      // --key value syntax or standalone flag
      const key = arg.slice(2)
      result[key] = true
      // Check if next arg is a value (not a flag starting with --)
      if (i + 1 < argv.length && !argv[i + 1].startsWith('--')) {
        result[key] = argv[i + 1]
        i += 2
      } else {
        i += 1
      }
    }
  }
  return result
}
